use std::collections::BinaryHeap;

fn solve(n: i64, edges: Vec<Vec<i64>>) -> i64 {
    let n = n as usize;
    let mut adj = vec![vec![]; n];
    for edge in edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        let s = edge[2];
        let e = edge[3];
        adj[u].push((v, s, e));
    }

    let mut dist = vec![i64::MAX; n];
    dist[0] = 0;

    let mut pq = BinaryHeap::new();
    pq.push((-0, 0));

    while let Some((current_time_neg, u)) = pq.pop() {
        let current_time = -current_time_neg;
        if u == n - 1 {
            return current_time;
        }
        if current_time > dist[u] {
            continue;
        }
        for (v, s, e) in &adj[u] {
            if current_time <= *e {
                let new_time = std::cmp::max(current_time, *s) + 1;
                if new_time < dist[*v] {
                    dist[*v] = new_time;
                    pq.push((-new_time, *v));
                }
            }
        }
    }

    -1
}
